    public void handleOrders(Client client, Object message)
    {
        // snapshot
        //     {
        //         "type": "snapshot",
        //         "tradingAccountId": "111309424211255",
        //         "dataType": "V1TAOrder",
        //         "data": [ ... ] // could be an empty list or a list of orders
        //     }
        //
        // update
        //     {
        //         "type": "update",
        //         "tradingAccountId": "111309424211255",
        //         "dataType": "V1TAOrder",
        //         "data": {
        //             "status": "OPEN",
        //             "createdAtTimestamp": "1751893427971",
        //             "quoteFee": "0.000000",
        //             "stopPrice": null,
        //             "quantityFilled": "0.00000000",
        //             "handle": null,
        //             "clientOrderId": null,
        //             "quantity": "0.10000000",
        //             "margin": false,
        //             "side": "BUY",
        //             "createdAtDatetime": "2025-07-07T13:03:47.971Z",
        //             "isLiquidation": false,
        //             "borrowedQuoteQuantity": null,
        //             "borrowedBaseQuantity": null,
        //             "timeInForce": "GTC",
        //             "borrowedQuantity": null,
        //             "baseFee": "0.000000",
        //             "quoteAmount": "0.0000000",
        //             "price": "0.0000000",
        //             "statusReason": "Order accepted",
        //             "type": "MKT",
        //             "statusReasonCode": 6014,
        //             "allowBorrow": false,
        //             "orderId": "862317981870850049",
        //             "publishedAtTimestamp": "1751893427975",
        //             "symbol": "ETHUSDT",
        //             "averageFillPrice": null
        //         }
        //     }
        //
        Object type = this.safeString(message, "type");
        Object rawOrders = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        if (Helpers.isTrue(Helpers.isEqual(type, "update")))
        {
            Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
            ((java.util.List<Object>)rawOrders).add(data); // update is a single order
        } else
        {
            rawOrders = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList())); // snapshot is a list of orders
        }
        if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.getArrayLength(rawOrders), 0)))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
            {
                Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
                this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            }
            Object orders = this.orders;
            Object symbols = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawOrders)); i++)
            {
                Object rawOrder = Helpers.GetValue(rawOrders, i);
                Object parsedOrder = this.parseOrder(rawOrder);
                Helpers.callDynamically(orders, "append", new Object[]{parsedOrder});
                Object symbol = this.safeString(parsedOrder, "symbol");
                if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                {
                    Helpers.addElementToObject(symbols, symbol, true);
                }
            }
            Object messageHash = "orders";
            client.resolve(orders, messageHash);
            Object keys = Helpers.objectKeys(symbols);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object hashSymbol = Helpers.GetValue(keys, i);
                Object symbolMessageHash = Helpers.add(Helpers.add(messageHash, "::"), hashSymbol);
                client.resolve(this.orders, symbolMessageHash);
            }
        }
    }

